int main() {
    int maxInt = findMax(10, 20);
    std::cout << "Max of 10 and 20 (int): " << maxInt << std::endl;
    double maxDouble = findMax(3.14, 2.71);
    std::cout << "Max of 3.14 and 2.71 (double): " << maxDouble << std::endl;
    char maxChar = findMax('a', 'z');
    std::cout << "Max of 'a' and 'z' (char): " << maxChar << std::endl;

    std::cout << "\n--- MyData Example (expect copy constructor calls) ---" << std::endl;
    class MyData {
    public:
        int value;
        std::string name;
        MyData(int v, std::string n) : value(v), name(std::move(n)) {}
        MyData(const MyData& other) : value(other.value), name(other.name + " (copied)") {
            std::cout << "MyData Copy Constructor: " << name << std::endl;
        }
        MyData(MyData&& other) noexcept : value(other.value), name(std::move(other.name)) {}
        MyData& operator=(const MyData& other) {
            if (this != &other) { value = other.value; name = other.name + " (assigned)"; }
            return *this;
        }
        bool operator>(const MyData& other) const { return value > other.value; }
    };
    std::ostream& operator<<(std::ostream& os, const MyData& md) { os << "{" << md.value << ", " << md.name << "}"; return os; }

    MyData d1(10, "Object1");
    MyData d2(20, "Object2");
    MyData maxMyData = findMax(d1, d2);
    std::cout << "Max of MyData: " << maxMyData << std::endl;
    std::cout << "--- End MyData Example ---\n" << std::endl;

    std::string s1 = "apple";
    std::string s2 = "banana";
    std::string maxString = findMax(s1, s2);
    std::cout << "Max of \"" << s1 << "\" and \"" << s2 << "\" (string): " << maxString << std::endl;
    return 0;
}
